import { Injectable, NotFoundException, ForbiddenException, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { CreateLessonDto } from './dto/lesson.dto';

@Injectable()
export class LessonsService {
  constructor(private prisma: PrismaService) {}

  async create(courseId: string, dto: CreateLessonDto, teacherId: string) {
    const course = await this.prisma.course.findUnique({ where: { id: courseId } });
    if (!course) throw new NotFoundException('Курс табылмады');
    if (course.teacherId !== teacherId) throw new ForbiddenException('Рұқсат жоқ');
    return this.prisma.lesson.create({ data: { ...dto, courseId } });
  }

  async findByCourse(courseId: string) {
    return this.prisma.lesson.findMany({
      where: { courseId },
      orderBy: { order: 'asc' },
    });
  }

  async createForModule(moduleId: string, dto: CreateLessonDto, teacherId: string) {
    const mod = await this.prisma.courseModule.findUnique({
      where: { id: moduleId },
      include: { course: true },
    });
    if (!mod) throw new NotFoundException('Бөлім табылмады');
    if (mod.course.teacherId !== teacherId) throw new ForbiddenException('Рұқсат жоқ');
    return this.prisma.lesson.create({ data: { ...dto, moduleId } });
  }

  async findByModule(moduleId: string) {
    return this.prisma.lesson.findMany({
      where: { moduleId },
      orderBy: { order: 'asc' },
      include: { steps: { orderBy: { order: 'asc' }, select: { id: true, type: true, order: true } } },
    });
  }

  async findById(id: string, userId?: string) {
    const lesson = await this.prisma.lesson.findUnique({
      where: { id },
      include: {
        steps: { orderBy: { order: 'asc' } },
      },
    });
    if (!lesson) throw new NotFoundException('Сабақ табылмады');

    // Block skipping only for old-style (course-direct) lessons
    if (userId && lesson.courseId && lesson.order > 1) {
      const prevLessons = await this.prisma.lesson.findMany({
        where: { courseId: lesson.courseId, order: { lt: lesson.order } },
        select: { id: true },
      });
      const completedCount = await this.prisma.lessonProgress.count({
        where: { userId, lessonId: { in: prevLessons.map((l) => l.id) } },
      });
      if (completedCount < prevLessons.length) {
        throw new ForbiddenException('Алдыңғы сабақтарды аяқтаңыз');
      }
    }

    // Track progress (fire-and-forget) — only for course-direct lessons
    if (userId && lesson.courseId) {
      this.prisma.lessonProgress.upsert({
        where: { userId_lessonId: { userId, lessonId: id } },
        update: { viewedAt: new Date() },
        create: { userId, courseId: lesson.courseId, lessonId: id },
      }).catch(() => {});
    }

    return lesson;
  }

  private async resolveTeacherId(lesson: any): Promise<string | undefined> {
    if (lesson.course) return lesson.course.teacherId;
    if (lesson.moduleId) {
      const mod = await this.prisma.courseModule.findUnique({
        where: { id: lesson.moduleId },
        include: { course: true },
      });
      return mod?.course?.teacherId;
    }
    return undefined;
  }

  async update(id: string, dto: Partial<CreateLessonDto>, teacherId: string) {
    const lesson = await this.prisma.lesson.findUnique({
      where: { id },
      include: { course: true },
    });
    if (!lesson) throw new NotFoundException('Сабақ табылмады');
    const ownerId = await this.resolveTeacherId(lesson);
    if (ownerId !== teacherId) throw new ForbiddenException('Рұқсат жоқ');
    return this.prisma.lesson.update({ where: { id }, data: dto });
  }

  async remove(id: string, teacherId: string) {
    const lesson = await this.prisma.lesson.findUnique({
      where: { id },
      include: { course: true },
    });
    if (!lesson) throw new NotFoundException('Сабақ табылмады');
    const ownerId = await this.resolveTeacherId(lesson);
    if (ownerId !== teacherId) throw new ForbiddenException('Рұқсат жоқ');
    await this.prisma.lesson.delete({ where: { id } });
    return { message: 'Сабақ жойылды' };
  }

  async getMyProgress(courseId: string, userId: string) {
    const lessons = await this.prisma.lesson.findMany({
      where: { courseId },
      orderBy: { order: 'asc' },
    });
    const progress = await this.prisma.lessonProgress.findMany({
      where: { courseId, userId },
    });
    const progressMap = new Map(progress.map((p) => [p.lessonId, p.viewedAt]));
    return lessons.map((lesson) => ({
      ...lesson,
      // Never expose the correct answer to the client
      assignmentAnswer: undefined,
      completed: progressMap.has(lesson.id),
      viewedAt: progressMap.get(lesson.id) ?? null,
    }));
  }

  /** Check the user's assignment answer. Returns correct: true/false. */
  async checkAssignment(lessonId: string, userId: string, userAnswer: string) {
    const lesson = await this.prisma.lesson.findUnique({ where: { id: lessonId } });
    if (!lesson) throw new NotFoundException('Сабақ табылмады');
    if (!lesson.assignmentAnswer) {
      throw new BadRequestException('Бұл сабақта тексерілетін тапсырма жоқ');
    }

    const normalize = (s: string) =>
      s.trim().toLowerCase().replace(/\s+/g, ' ').replace(/[;"']/g, '');

    const correct = normalize(userAnswer) === normalize(lesson.assignmentAnswer);

    // If correct: mark lesson as completed
    if (correct && lesson.courseId) {
      await this.prisma.lessonProgress.upsert({
        where: { userId_lessonId: { userId, lessonId } },
        update: { viewedAt: new Date() },
        create: { userId, courseId: lesson.courseId, lessonId },
      });
    }

    return { correct, feedback: correct ? 'Дұрыс!  Сабақ аяқталды.' : 'Қате. Қайта көріңіз және 15 секундтан кейін қайталаңыз.' };
  }

  /** Mark lesson as completed without assignment check (reading-type lessons). */
  async markCompleted(lessonId: string, userId: string) {
    const lesson = await this.prisma.lesson.findUnique({ where: { id: lessonId } });
    if (!lesson) throw new NotFoundException('Сабақ табылмады');
    if (lesson.courseId) {
      await this.prisma.lessonProgress.upsert({
        where: { userId_lessonId: { userId, lessonId } },
        update: { viewedAt: new Date() },
        create: { userId, courseId: lesson.courseId, lessonId },
      });
    }
    return { message: 'Сабақ аяқталды' };
  }
}

import { Injectable, NotFoundException, ForbiddenException, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { CreateLessonDto } from './dto/lesson.dto';

@Injectable()
export class LessonsService {
  constructor(private prisma: PrismaService) {}

  async create(courseId: string, dto: CreateLessonDto, teacherId: string) {
    const course = await this.prisma.course.findUnique({ where: { id: courseId } });
    if (!course) throw new NotFoundException('Курс табылмады');
    if (course.teacherId !== teacherId) throw new ForbiddenException('Рұқсат жоқ');
    return this.prisma.lesson.create({ data: { ...dto, courseId } });
  }

  async findByCourse(courseId: string) {
    return this.prisma.lesson.findMany({
      where: { courseId },
      orderBy: { order: 'asc' },
    });
  }

  async createForModule(moduleId: string, dto: CreateLessonDto, teacherId: string) {
    const mod = await this.prisma.courseModule.findUnique({
      where: { id: moduleId },
      include: { course: true },
    });
    if (!mod) throw new NotFoundException('Бөлім табылмады');
    if (mod.course.teacherId !== teacherId) throw new ForbiddenException('Рұқсат жоқ');
    return this.prisma.lesson.create({ data: { ...dto, moduleId } });
  }

  async findByModule(moduleId: string) {
    return this.prisma.lesson.findMany({
      where: { moduleId },
      orderBy: { order: 'asc' },
      include: { steps: { orderBy: { order: 'asc' }, select: { id: true, type: true, order: true } } },
    });
  }

  async findById(id: string, userId?: string) {
    const lesson = await this.prisma.lesson.findUnique({
      where: { id },
      include: {
        steps: { orderBy: { order: 'asc' } },
      },
    });
    if (!lesson) throw new NotFoundException('Сабақ табылмады');

    // Block skipping only for old-style (course-direct) lessons
    if (userId && lesson.courseId && lesson.order > 1) {
      const prevLessons = await this.prisma.lesson.findMany({
        where: { courseId: lesson.courseId, order: { lt: lesson.order } },
        select: { id: true },
      });
      const completedCount = await this.prisma.lessonProgress.count({
        where: { userId, lessonId: { in: prevLessons.map((l) => l.id) } },
      });
      if (completedCount < prevLessons.length) {
        throw new ForbiddenException('Алдыңғы сабақтарды аяқтаңыз');
      }
    }

    // Track progress (fire-and-forget) — only for course-direct lessons
    if (userId && lesson.courseId) {
      this.prisma.lessonProgress.upsert({
        where: { userId_lessonId: { userId, lessonId: id } },
        update: { viewedAt: new Date() },
        create: { userId, courseId: lesson.courseId, lessonId: id },
      }).catch(() => {});
    }

    return lesson;
  }

  private async resolveTeacherId(lesson: any): Promise<string | undefined> {
    if (lesson.course) return lesson.course.teacherId;
    if (lesson.moduleId) {
      const mod = await this.prisma.courseModule.findUnique({
        where: { id: lesson.moduleId },
        include: { course: true },
      });
      return mod?.course?.teacherId;
    }
    return undefined;
  }

  async update(id: string, dto: Partial<CreateLessonDto>, teacherId: string) {
    const lesson = await this.prisma.lesson.findUnique({
      where: { id },
      include: { course: true },
    });
    if (!lesson) throw new NotFoundException('Сабақ табылмады');
    const ownerId = await this.resolveTeacherId(lesson);
    if (ownerId !== teacherId) throw new ForbiddenException('Рұқсат жоқ');
    return this.prisma.lesson.update({ where: { id }, data: dto });
  }

  async remove(id: string, teacherId: string) {
    const lesson = await this.prisma.lesson.findUnique({
      where: { id },
      include: { course: true },
    });
    if (!lesson) throw new NotFoundException('Сабақ табылмады');
    const ownerId = await this.resolveTeacherId(lesson);
    if (ownerId !== teacherId) throw new ForbiddenException('Рұқсат жоқ');
    await this.prisma.lesson.delete({ where: { id } });
    return { message: 'Сабақ жойылды' };
  }

  async getMyProgress(courseId: string, userId: string) {
    const lessons = await this.prisma.lesson.findMany({
      where: { courseId },
      orderBy: { order: 'asc' },
    });
    const progress = await this.prisma.lessonProgress.findMany({
      where: { courseId, userId },
    });
    const progressMap = new Map(progress.map((p) => [p.lessonId, p.viewedAt]));
    return lessons.map((lesson) => ({
      ...lesson,
      // Never expose the correct answer to the client
      assignmentAnswer: undefined,
      completed: progressMap.has(lesson.id),
      viewedAt: progressMap.get(lesson.id) ?? null,
    }));
  }

  /** Check the user's assignment answer. Returns correct: true/false. */
  async checkAssignment(lessonId: string, userId: string, userAnswer: string) {
    const lesson = await this.prisma.lesson.findUnique({ where: { id: lessonId } });
    if (!lesson) throw new NotFoundException('Сабақ табылмады');
    if (!lesson.assignmentAnswer) {
      throw new BadRequestException('Бұл сабақта тексерілетін тапсырма жоқ');
    }

    const normalize = (s: string) =>
      s.trim().toLowerCase().replace(/\s+/g, ' ').replace(/[;"'.,!?]/g, '');

    const normalizedAnswer = normalize(userAnswer);
    const expectedRaw = lesson.assignmentAnswer;

    // Support pipe-separated keywords: "python|питон|пайтон"
    // Also support "any" keyword — accept any non-empty answer (open-ended)
    let correct = false;
    if (expectedRaw.trim().toLowerCase() === 'any' || expectedRaw.trim().toLowerCase() === 'кез келген') {
      correct = normalizedAnswer.length >= 10; // at least 10 chars for open-ended
    } else if (expectedRaw.includes('|')) {
      const keywords = expectedRaw.split('|').map(k => normalize(k));
      correct = keywords.some(kw => normalizedAnswer.includes(kw));
    } else {
      // Contains check: user answer must contain the expected keyword/phrase
      correct = normalizedAnswer.includes(normalize(expectedRaw));
    }

    // If correct: mark lesson as completed
    if (correct && lesson.courseId) {
      await this.prisma.lessonProgress.upsert({
        where: { userId_lessonId: { userId, lessonId } },
        update: { viewedAt: new Date() },
        create: { userId, courseId: lesson.courseId, lessonId },
      });
    }

    return { correct, feedback: correct ? 'Дұрыс!  Сабақ аяқталды.' : 'Қате. Қайта көріңіз және 15 секундтан кейін қайталаңыз.' };
  }

  /** Mark lesson as completed without assignment check (reading-type lessons). */
  async markCompleted(lessonId: string, userId: string) {
    const lesson = await this.prisma.lesson.findUnique({ where: { id: lessonId } });
    if (!lesson) throw new NotFoundException('Сабақ табылмады');
    if (lesson.courseId) {
      await this.prisma.lessonProgress.upsert({
        where: { userId_lessonId: { userId, lessonId } },
        update: { viewedAt: new Date() },
        create: { userId, courseId: lesson.courseId, lessonId },
      });
    }
    return { message: 'Сабақ аяқталды' };
  }
}

'use client';

import { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import api from '@/lib/api';
import toast from 'react-hot-toast';
import Link from 'next/link';

interface LessonProgress {
  id: string;
  title: string;
  order: number;
  completed: boolean;
}

interface Exam {
  id: string;
  title: string;
  duration: number;
  passScore: number;
}

interface Course {
  id: string;
  title: string;
  description?: string;
  teacher: { name: string };
  lessons: { id: string; title: string; order: number }[];
  modules: {
    id: string;
    title: string;
    order: number;
    lessons: {
      id: string;
      title: string;
      order: number;
      steps: { id: string; type: string; order: number }[];
    }[];
  }[];
  exams: Exam[];
}

export default function CourseDetailPage() {
  const { id } = useParams();
  const [course, setCourse] = useState<Course | null>(null);
  const [progress, setProgress] = useState<LessonProgress[]>([]);
  const [stepProgress, setStepProgress] = useState<{ total: number; completed: number; percent: number } | null>(null);
  const [loading, setLoading] = useState(true);
  const router = useRouter();

  useEffect(() => {
    const load = async () => {
      try {
        const [courseRes, progressRes, stepProgressRes] = await Promise.allSettled([
          api.get(`/courses/${id}`),
          api.get(`/courses/${id}/lessons/progress/my`),
          api.get(`/submissions/course/${id}/progress`),
        ]);
        if (courseRes.status === 'fulfilled') setCourse(courseRes.value.data);
        else throw new Error('Course not found');
        if (progressRes.status === 'fulfilled') setProgress(progressRes.value.data);
        if (stepProgressRes.status === 'fulfilled') setStepProgress(stepProgressRes.value.data);
      } catch {
        toast.error('Курс табылмады');
        router.push('/dashboard/courses');
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [id]);

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (!course) return null;

  const completedIds = new Set(progress.filter((l) => l.completed).map((l) => l.id));
  const allLessonsCompleted = course.lessons.length > 0 && course.lessons.every((l) => completedIds.has(l.id));
  const completedCount = completedIds.size;

  // Does this course have modules with steps?
  const hasModules = (course.modules ?? []).length > 0;
  const totalSteps = (course.modules ?? []).reduce(
    (sum, m) => sum + m.lessons.reduce((ls, l) => ls + l.steps.length, 0),
    0,
  );
  const firstStepId = hasModules
    ? (course.modules[0]?.lessons[0]?.steps[0]?.id ?? null)
    : null;

  // A lesson is accessible if it's first OR the previous lesson is completed
  const isAccessible = (lesson: { id: string; order: number }) => {
    if (lesson.order === 1) return true;
    const prev = course.lessons.find((l) => l.order === lesson.order - 1);
    return prev ? completedIds.has(prev.id) : false;
  };

  return (
    <div className="max-w-4xl">
      <div className="mb-6">
        <Link href="/dashboard/courses" className="text-primary-600 hover:underline text-sm">
          ← Курстарға оралу
        </Link>
      </div>

      <div className="card mb-6">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">{course.title}</h1>
        {course.description && <p className="text-gray-600 mb-4">{course.description}</p>}
        <p className="text-sm text-gray-400">Мұғалім: {course.teacher.name}</p>

        {/* Step-based progress for module courses */}
        {hasModules && stepProgress && stepProgress.total > 0 && (
          <div className="mt-4">
            <div className="flex justify-between text-sm text-gray-500 mb-1">
              <span>Қадам прогресі</span>
              <span>{stepProgress.completed}/{stepProgress.total} қадам ({stepProgress.percent}%)</span>
            </div>
            <div className="h-2.5 bg-gray-200 rounded-full overflow-hidden">
              <div
                className="h-full bg-primary-500 rounded-full transition-all duration-500"
                style={{ width: `${stepProgress.percent}%` }}
              />
            </div>
          </div>
        )}

        {/* Lesson-based progress for flat courses */}
        {!hasModules && course.lessons.length > 0 && (
          <div className="mt-4">
            <div className="flex justify-between text-sm text-gray-500 mb-1">
              <span>Прогресс</span>
              <span>{completedCount}/{course.lessons.length} сабақ</span>
            </div>
            <div className="h-2.5 bg-gray-200 rounded-full overflow-hidden">
              <div
                className="h-full bg-green-500 rounded-full transition-all duration-500"
                style={{ width: `${(completedCount / course.lessons.length) * 100}%` }}
              />
            </div>
          </div>
        )}
      </div>

      {/* Module-based course content */}
      {hasModules && (
        <div className="card mb-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-xl font-semibold">Курс бағдарламасы ({totalSteps} қадам)</h2>
            {firstStepId && (
              <Link
                href={`/dashboard/courses/${course.id}/learn${firstStepId ? `?step=${firstStepId}` : ''}`}
                className="btn-primary text-sm px-4 py-2"
              >
                {stepProgress && stepProgress.completed > 0 ? '▶ Жалғастыру' : ' Оқуды бастау'}
              </Link>
            )}
          </div>
          <div className="space-y-3">
            {(course.modules ?? []).map((mod) => (
              <details key={mod.id} className="bg-gray-50 rounded-xl border border-gray-100" open>
                <summary className="px-4 py-3 cursor-pointer font-medium text-gray-800 flex items-center gap-2">
                  <span className="text-primary-600"></span>
                  {mod.order}. {mod.title}
                  <span className="ml-auto text-xs text-gray-400">{mod.lessons.length} сабақ</span>
                </summary>
                <div className="px-4 pb-3 space-y-2">
                  {mod.lessons.map((lesson) => (
                    <div key={lesson.id} className="pl-4 border-l-2 border-gray-200 py-1">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-sm font-medium text-gray-700"> {lesson.title}</span>
                        <span className="text-xs text-gray-400 ml-auto">{lesson.steps.length} қадам</span>
                      </div>
                      <div className="flex flex-wrap gap-1.5">
                        {lesson.steps.map((step) => (
                          <Link
                            key={step.id}
                            href={`/dashboard/courses/${course.id}/learn?step=${step.id}`}
                            className="text-xs px-2 py-1 bg-white border border-gray-200 rounded-lg hover:border-primary-400 hover:text-primary-600 transition"
                          >
                            {step.type === 'VIDEO' ? '▶️' : step.type === 'TASK' ? '✏️' : ''} {step.order}-қадам
                          </Link>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </details>
            ))}
          </div>
        </div>
      )}

      {/* All steps/lessons done → take exam banner */}
      {((hasModules && stepProgress && stepProgress.percent >= 100) || (!hasModules && allLessonsCompleted)) && course.exams.length > 0 && (
        <div className="mb-6 p-5 bg-green-50 border border-green-200 rounded-xl flex items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <span className="text-3xl"></span>
            <div>
              <p className="font-semibold text-green-800">
                {hasModules ? 'Барлық қадамдарды аяқтадыңыз!' : 'Барлық сабақтарды аяқтадыңыз!'}
              </p>
              <p className="text-sm text-green-600">Енді емтиханды тапсыра аласыз</p>
            </div>
          </div>
          <Link href={`/dashboard/exam/${course.exams[0].id}`} className="btn-primary whitespace-nowrap">
            Емтиханды бастау →
          </Link>
        </div>
      )}

      <div className={`grid grid-cols-1 ${!hasModules ? 'md:grid-cols-2' : ''} gap-6`}>
        {/* Flat lessons — only shown for non-module courses */}
        {!hasModules && (
        <div className="card">
          <h2 className="text-xl font-semibold mb-4">Сабақтар ({course.lessons.length})</h2>
          {course.lessons.length === 0 ? (
            <p className="text-gray-400">Сабақ жоқ</p>
          ) : (
            <ul className="space-y-2">
              {course.lessons.map((lesson) => {
                const done = completedIds.has(lesson.id);
                const accessible = isAccessible(lesson);
                return (
                  <li key={lesson.id}>
                    {accessible ? (
                      <Link
                        href={`/dashboard/courses/${course.id}/lessons/${lesson.id}`}
                        className={`flex items-center gap-3 p-3 rounded-lg border transition-colors ${
                          done
                            ? 'bg-green-50 border-green-200 hover:bg-green-100'
                            : 'bg-gray-50 border-transparent hover:bg-primary-50 hover:border-primary-200'
                        }`}
                      >
                        <span className={`w-7 h-7 flex-shrink-0 rounded-full text-sm font-bold flex items-center justify-center ${
                          done ? 'bg-green-500 text-white' : 'bg-primary-100 text-primary-700'
                        }`}>
                          {done ? '✓' : lesson.order}
                        </span>
                        <span className={`text-sm font-medium ${done ? 'text-green-800' : 'text-gray-800'}`}>
                          {lesson.title}
                        </span>
                        <span className="ml-auto text-xs text-primary-600">
                          {done ? '✓ Оқылды' : 'Оқу →'}
                        </span>
                      </Link>
                    ) : (
                      <div className="flex items-center gap-3 p-3 rounded-lg border border-transparent bg-gray-50 opacity-50 cursor-not-allowed">
                        <span className="w-7 h-7 flex-shrink-0 rounded-full bg-gray-200 text-gray-500 text-sm font-bold flex items-center justify-center">

                        </span>
                        <span className="text-sm font-medium text-gray-500">{lesson.title}</span>
                        <span className="ml-auto text-xs text-gray-400">Жабық</span>
                      </div>
                    )}
                  </li>
                );
              })}
            </ul>
          )}
        </div>
        )}

        {/* Exams */}
        <div className="card">
          <h2 className="text-xl font-semibold mb-4">Емтихандар ({course.exams.length})</h2>
          {course.exams.length === 0 ? (
            <p className="text-gray-400">Емтихан жоқ</p>
          ) : (
            <ul className="space-y-3">
              {course.exams.map((exam) => {
                const canTakeExam = hasModules
                  ? (stepProgress?.percent ?? 0) >= 100
                  : allLessonsCompleted;
                return (
                  <li key={exam.id} className="p-3 bg-gray-50 rounded-lg">
                    <p className="font-medium text-gray-800">{exam.title}</p>
                    <div className="flex gap-4 text-xs text-gray-500 mt-1">
                      <span>⏱ {exam.duration} мин</span>
                      <span>✓ Өту балы: {exam.passScore}%</span>
                    </div>
                    {canTakeExam ? (
                      <Link
                        href={`/dashboard/exam/${exam.id}`}
                        className="mt-2 inline-block btn-primary text-sm px-3 py-1.5"
                      >
                        Емтиханды бастау
                      </Link>
                    ) : (
                      <div className="mt-2">
                        <span className="inline-block text-xs text-gray-400 bg-gray-100 px-3 py-1.5 rounded-lg">
                           {hasModules ? 'Барлық қадамдарды аяқтаңыз' : 'Барлық сабақтарды аяқтаңыз'}
                        </span>
                      </div>
                    )}
                  </li>
                );
              })}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import api from '@/lib/api';
import toast from 'react-hot-toast';
import Link from 'next/link';

interface LessonProgress {
  id: string;
  title: string;
  order: number;
  completed: boolean;
}

interface Exam {
  id: string;
  title: string;
  duration: number;
  passScore: number;
}

interface Course {
  id: string;
  title: string;
  description?: string;
  teacher: { name: string };
  lessons: { id: string; title: string; order: number }[];
  modules: {
    id: string;
    title: string;
    order: number;
    lessons: {
      id: string;
      title: string;
      order: number;
      steps: { id: string; type: string; order: number }[];
    }[];
  }[];
  exams: Exam[];
}

export default function CourseDetailPage() {
  const { id } = useParams();
  const [course, setCourse] = useState<Course | null>(null);
  const [progress, setProgress] = useState<LessonProgress[]>([]);
  const [stepProgress, setStepProgress] = useState<{ total: number; completed: number; percent: number } | null>(null);
  const [loading, setLoading] = useState(true);
  const router = useRouter();

  useEffect(() => {
    const load = async () => {
      try {
        const [courseRes, progressRes, stepProgressRes] = await Promise.allSettled([
          api.get(`/courses/${id}`),
          api.get(`/courses/${id}/lessons/progress/my`),
          api.get(`/submissions/course/${id}/progress`),
        ]);
        if (courseRes.status === 'fulfilled') setCourse(courseRes.value.data);
        else throw new Error('Course not found');
        if (progressRes.status === 'fulfilled') setProgress(progressRes.value.data);
        if (stepProgressRes.status === 'fulfilled') setStepProgress(stepProgressRes.value.data);
      } catch {
        toast.error('Курс табылмады');
        router.push('/dashboard/courses');
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [id]);

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (!course) return null;

  const completedIds = new Set(progress.filter((l) => l.completed).map((l) => l.id));
  const allLessonsCompleted = course.lessons.length > 0 && course.lessons.every((l) => completedIds.has(l.id));
  const completedCount = completedIds.size;
  const hasModules = (course.modules ?? []).length > 0;
  // Total lessons across all modules
  const totalModuleLessons = (course.modules ?? []).reduce((sum, m) => sum + m.lessons.length, 0);
  // First lesson in first module
  const firstModuleLesson = hasModules ? (course.modules[0]?.lessons[0] ?? null) : null;

  // All lessons from modules for progress tracking
  const allModuleLessonIds = (course.modules ?? []).flatMap((m) => m.lessons.map((l) => l.id));
  const moduleLessonsCompleted = allModuleLessonIds.filter((id) => completedIds.has(id)).length;
  const allModuleLessonsDone = totalModuleLessons > 0 && moduleLessonsCompleted >= totalModuleLessons;

  // A lesson is accessible: order=1 is always open, others need prev completed
  const isAccessible = (lesson: { id: string; order: number }) => {
    if (lesson.order === 1) return true;
    const prev = course.lessons.find((l) => l.order === lesson.order - 1);
    return prev ? completedIds.has(prev.id) : false;
  };

  // Module lesson accessible: first lesson of module always open; others sequential
  const isModuleLessonAccessible = (modIdx: number, lessonIdx: number): boolean => {
    if (modIdx === 0 && lessonIdx === 0) return true;
    const mods = course.modules ?? [];
    // get previous lesson id
    let prevId: string | null = null;
    if (lessonIdx > 0) {
      prevId = mods[modIdx]?.lessons[lessonIdx - 1]?.id ?? null;
    } else if (modIdx > 0) {
      const prevMod = mods[modIdx - 1];
      prevId = prevMod?.lessons[prevMod.lessons.length - 1]?.id ?? null;
    }
    return prevId ? completedIds.has(prevId) : false;
  };

  return (
    <div className="max-w-4xl">
      <div className="mb-6">
        <Link href="/dashboard/courses" className="text-primary-600 hover:underline text-sm">
          ← Курстарға оралу
        </Link>
      </div>

      <div className="card mb-6">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">{course.title}</h1>
        {course.description && <p className="text-gray-600 mb-4">{course.description}</p>}
        <p className="text-sm text-gray-400">Мұғалім: {course.teacher.name}</p>

        {/* Progress bar — works for both module and flat courses */}
        {(hasModules ? totalModuleLessons : course.lessons.length) > 0 && (
          <div className="mt-4">
            <div className="flex justify-between text-sm text-gray-500 mb-1">
              <span>Прогресс</span>
              <span>
                {hasModules ? moduleLessonsCompleted : completedCount}/
                {hasModules ? totalModuleLessons : course.lessons.length} сабақ
              </span>
            </div>
            <div className="h-2.5 bg-gray-200 rounded-full overflow-hidden">
              <div
                className="h-full bg-green-500 rounded-full transition-all duration-500"
                style={{
                  width: `${hasModules
                    ? (totalModuleLessons > 0 ? (moduleLessonsCompleted / totalModuleLessons) * 100 : 0)
                    : (course.lessons.length > 0 ? (completedCount / course.lessons.length) * 100 : 0)
                  }%`
                }}
              />
            </div>
          </div>
        )}
      </div>

      {/* Module-based course content — lessons with direct links */}
      {hasModules && (
        <div className="card mb-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-xl font-semibold">
              Курс бағдарламасы
              <span className="ml-2 text-sm font-normal text-gray-500">
                ({totalModuleLessons} сабақ · {(course.modules ?? []).length} модуль)
              </span>
            </h2>
            {firstModuleLesson && (
              <Link
                href={`/dashboard/courses/${course.id}/lessons/${firstModuleLesson.id}`}
                className="btn-primary text-sm px-4 py-2"
              >
                {moduleLessonsCompleted > 0 ? '▶ Жалғастыру' : ' Оқуды бастау'}
              </Link>
            )}
          </div>
          <div className="space-y-3">
            {(course.modules ?? []).map((mod, modIdx) => {
              const modCompletedCount = mod.lessons.filter((l) => completedIds.has(l.id)).length;
              const modDone = modCompletedCount === mod.lessons.length && mod.lessons.length > 0;
              return (
                <details key={mod.id} className="bg-gray-50 rounded-xl border border-gray-100" open={modIdx === 0}>
                  <summary className="px-4 py-3 cursor-pointer font-medium text-gray-800 flex items-center gap-2 select-none">
                    <span>{modDone ? '✅' : ''}</span>
                    <span>{mod.order}. {mod.title}</span>
                    <span className="ml-auto text-xs text-gray-400">
                      {modCompletedCount}/{mod.lessons.length} сабақ
                    </span>
                  </summary>
                  <div className="px-4 pb-3 space-y-1.5">
                    {mod.lessons.map((lesson, lessonIdx) => {
                      const done = completedIds.has(lesson.id);
                      const accessible = isModuleLessonAccessible(modIdx, lessonIdx);
                      const isTest = lesson.title.toLowerCase().includes('тест') ||
                                     lesson.title.toLowerCase().includes('test') ||
                                     lesson.title.toLowerCase().includes('модуль тест') ||
                                     (lessonIdx + 1) % 5 === 0;
                      if (!accessible) {
                        return (
                          <div key={lesson.id} className="flex items-center gap-3 px-3 py-2 rounded-lg text-sm text-gray-400 opacity-50 cursor-not-allowed">
                            <span className="w-6 h-6 flex-shrink-0 rounded-full border-2 border-gray-200 flex items-center justify-center text-xs"></span>
                            <span className="truncate">{lesson.title}</span>
                          </div>
                        );
                      }
                      return (
                        <Link
                          key={lesson.id}
                          href={`/dashboard/courses/${course.id}/lessons/${lesson.id}`}
                          className={`flex items-center gap-3 px-3 py-2 rounded-lg text-sm transition-colors ${
                            done
                              ? 'bg-green-50 border border-green-200 text-green-800 hover:bg-green-100'
                              : isTest
                              ? 'bg-amber-50 border border-amber-200 text-amber-800 hover:bg-amber-100'
                              : 'bg-white border border-gray-200 text-gray-700 hover:border-primary-300 hover:text-primary-700'
                          }`}
                        >
                          <span className={`w-6 h-6 flex-shrink-0 rounded-full flex items-center justify-center text-xs font-bold ${
                            done ? 'bg-green-500 text-white' : isTest ? 'bg-amber-400 text-white' : 'bg-primary-100 text-primary-700'
                          }`}>
                            {done ? '✓' : isTest ? '' : lesson.order}
                          </span>
                          <span className="truncate flex-1">{lesson.title}</span>
                          {isTest && !done && <span className="text-xs text-amber-600 flex-shrink-0">Мини-тест</span>}
                          {done && <span className="text-xs text-green-600 flex-shrink-0">✓ Орындалды</span>}
                          {!done && !isTest && <span className="text-xs text-primary-500 flex-shrink-0">→</span>}
                        </Link>
                      );
                    })}
                  </div>
                </details>
              );
            })}
          </div>
        </div>
      )}

      {/* All lessons done → take exam banner */}
      {((hasModules && allModuleLessonsDone) || (!hasModules && allLessonsCompleted)) && course.exams.length > 0 && (
        <div className="mb-6 p-5 bg-green-50 border border-green-200 rounded-xl flex items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <span className="text-3xl"></span>
            <div>
              <p className="font-semibold text-green-800">Барлық сабақтарды аяқтадыңыз!</p>
              <p className="text-sm text-green-600">Енді емтиханды тапсыра аласыз</p>
            </div>
          </div>
          <Link href={`/dashboard/exam/${course.exams[0].id}`} className="btn-primary whitespace-nowrap">
            Емтиханды бастау →
          </Link>
        </div>
      )}

      <div className={`grid grid-cols-1 ${!hasModules ? 'md:grid-cols-2' : ''} gap-6`}>
        {/* Flat lessons — only shown for non-module courses */}
        {!hasModules && (
        <div className="card">
          <h2 className="text-xl font-semibold mb-4">Сабақтар ({course.lessons.length})</h2>
          {course.lessons.length === 0 ? (
            <p className="text-gray-400">Сабақ жоқ</p>
          ) : (
            <ul className="space-y-2">
              {course.lessons.map((lesson) => {
                const done = completedIds.has(lesson.id);
                const accessible = isAccessible(lesson);
                return (
                  <li key={lesson.id}>
                    {accessible ? (
                      <Link
                        href={`/dashboard/courses/${course.id}/lessons/${lesson.id}`}
                        className={`flex items-center gap-3 p-3 rounded-lg border transition-colors ${
                          done
                            ? 'bg-green-50 border-green-200 hover:bg-green-100'
                            : 'bg-gray-50 border-transparent hover:bg-primary-50 hover:border-primary-200'
                        }`}
                      >
                        <span className={`w-7 h-7 flex-shrink-0 rounded-full text-sm font-bold flex items-center justify-center ${
                          done ? 'bg-green-500 text-white' : 'bg-primary-100 text-primary-700'
                        }`}>
                          {done ? '✓' : lesson.order}
                        </span>
                        <span className={`text-sm font-medium ${done ? 'text-green-800' : 'text-gray-800'}`}>
                          {lesson.title}
                        </span>
                        <span className="ml-auto text-xs text-primary-600">
                          {done ? '✓ Оқылды' : 'Оқу →'}
                        </span>
                      </Link>
                    ) : (
                      <div className="flex items-center gap-3 p-3 rounded-lg border border-transparent bg-gray-50 opacity-50 cursor-not-allowed">
                        <span className="w-7 h-7 flex-shrink-0 rounded-full bg-gray-200 text-gray-500 text-sm font-bold flex items-center justify-center">

                        </span>
                        <span className="text-sm font-medium text-gray-500">{lesson.title}</span>
                        <span className="ml-auto text-xs text-gray-400">Жабық</span>
                      </div>
                    )}
                  </li>
                );
              })}
            </ul>
          )}
        </div>
        )}

        {/* Exams */}
        <div className="card">
          <h2 className="text-xl font-semibold mb-4">Емтихандар ({course.exams.length})</h2>
          {course.exams.length === 0 ? (
            <p className="text-gray-400">Емтихан жоқ</p>
          ) : (
            <ul className="space-y-3">
              {course.exams.map((exam) => {
                const canTakeExam = hasModules
                  ? allModuleLessonsDone
                  : allLessonsCompleted;
                return (
                  <li key={exam.id} className="p-3 bg-gray-50 rounded-lg">
                    <p className="font-medium text-gray-800">{exam.title}</p>
                    <div className="flex gap-4 text-xs text-gray-500 mt-1">
                      <span>⏱ {exam.duration} мин</span>
                      <span>✓ Өту балы: {exam.passScore}%</span>
                    </div>
                    {canTakeExam ? (
                      <Link
                        href={`/dashboard/exam/${exam.id}`}
                        className="mt-2 inline-block btn-primary text-sm px-3 py-1.5"
                      >
                        Емтиханды бастау
                      </Link>
                    ) : (
                      <div className="mt-2">
                        <span className="inline-block text-xs text-gray-400 bg-gray-100 px-3 py-1.5 rounded-lg">
                           {hasModules ? 'Барлық қадамдарды аяқтаңыз' : 'Барлық сабақтарды аяқтаңыз'}
                        </span>
                      </div>
                    )}
                  </li>
                );
              })}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import api from '@/lib/api';
import Link from 'next/link';
import toast from 'react-hot-toast';

interface Answer {
  id: string;
  answer: string;
  isCorrect: boolean | null;
  question: {
    id: string;
    text: string;
    type: string;
    options: string[] | null;
    answer: string;
  };
}

interface Attempt {
  id: string;
  score: number | null;
  trustScore: number;
  status: string;
  startedAt: string;
  finishedAt: string | null;
  exam: {
    id: string;
    title: string;
    passScore: number;
    duration: number;
  };
  answers: Answer[];
  events: { id: string; type: string; timestamp: string }[];
}

export default function AttemptReviewPage() {
  const { attemptId } = useParams<{ attemptId: string }>();
  const router = useRouter();
  const [attempt, setAttempt] = useState<Attempt | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api
      .get(`/attempts/${attemptId}`)
      .then(({ data }) => setAttempt(data))
      .catch(() => {
        toast.error('Жуктеу катесі');
        router.push('/dashboard/my-attempts');
      })
      .finally(() => setLoading(false));
  }, [attemptId]);

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (!attempt) return null;

  const passed = (attempt.score ?? 0) >= attempt.exam.passScore;
  const correctCount = attempt.answers.filter((a) => a.isCorrect).length;

  return (
    <div className="max-w-4xl">
      <div className="mb-6">
        <Link href="/dashboard/my-attempts" className="text-primary-600 hover:underline text-sm">
          ← Natijelerge oralyу
        </Link>
      </div>

      {/* Summary card */}
      <div className={`card mb-6 border-2 ${passed ? 'border-green-400' : 'border-red-400'}`}>
        <div className="flex flex-wrap justify-between items-start gap-4">
          <div>
            <h1 className="text-xl font-bold text-gray-900">{attempt.exam.title}</h1>
            <p className="text-gray-500 text-sm mt-1">
              {attempt.startedAt ? new Date(attempt.startedAt).toLocaleString('kk-KZ') : ''}
            </p>
          </div>
          <div className={`text-3xl font-bold ${passed ? 'text-green-600' : 'text-red-600'}`}>
            {attempt.score ?? 0}%
            <p className="text-sm font-normal text-gray-500">Otu: {attempt.exam.passScore}%</p>
          </div>
        </div>
        <div className="flex flex-wrap gap-6 mt-4 text-sm">
          <div>
            <span className="text-gray-500">Natije: </span>
            {passed ? (
              <span className="text-green-600 font-semibold">Otti</span>
            ) : (
              <span className="text-red-600 font-semibold">Otpedi</span>
            )}
          </div>
          <div>
            <span className="text-gray-500">Durys zhauaptar: </span>
            <span className="font-semibold">{correctCount}/{attempt.answers.length}</span>
          </div>
          <div>
            <span className="text-gray-500">Trust Score: </span>
            <span className={`font-semibold ${attempt.trustScore >= 80 ? 'text-green-600' : attempt.trustScore >= 50 ? 'text-yellow-600' : 'text-red-600'}`}>
              {attempt.trustScore}/100
            </span>
          </div>
          {attempt.events.length > 0 && (
            <div>
              <span className="text-gray-500">Is-sharalar: </span>
              <span className="font-semibold text-orange-600">{attempt.events.length}</span>
            </div>
          )}
        </div>
      </div>

      {/* Answers */}
      <div className="space-y-4">
        <h2 className="text-lg font-semibold text-gray-900 mb-2">Surаktar men zhauaptar</h2>
        {attempt.answers.length === 0 ? (
          <p className="text-gray-400 text-center py-8">Zhauap zhok</p>
        ) : (
          attempt.answers.map((ans, idx) => (
            <div
              key={ans.id}
              className={`card border-l-4 ${
                ans.isCorrect === true
                  ? 'border-l-green-500'
                  : ans.isCorrect === false
                  ? 'border-l-red-500'
                  : 'border-l-gray-300'
              }`}
            >
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1 min-w-0">
                  <p className="font-medium text-gray-900 mb-2">
                    <span className="text-primary-600 mr-2">{idx + 1}.</span>
                    {ans.question.text}
                  </p>

                  {/* Options for choice questions */}
                  {ans.question.options && ans.question.options.length > 0 && (
                    <div className="space-y-1 mb-3">
                      {ans.question.options.map((opt, optIdx) => {
                        const isUserAnswer = ans.answer.split(',').map((s) => s.trim()).includes(opt);
                        const isCorrectAnswer = ans.question.answer.split(',').map((s) => s.trim()).includes(opt);
                        return (
                          <div
                            key={optIdx}
                            className={`flex items-center gap-2 px-3 py-1.5 rounded text-sm ${
                              isCorrectAnswer
                                ? 'bg-green-100 text-green-800'
                                : isUserAnswer
                                ? 'bg-red-100 text-red-800'
                                : 'text-gray-600'
                            }`}
                          >
                            <span>{isCorrectAnswer ? '✓' : isUserAnswer ? '✗' : '○'}</span>
                            <span>{opt}</span>
                            {isUserAnswer && !isCorrectAnswer && <span className="ml-auto text-xs">Sizdin zhauap</span>}
                            {isCorrectAnswer && <span className="ml-auto text-xs font-medium">Durys zhaup</span>}
                          </div>
                        );
                      })}
                    </div>
                  )}

                  {/* Text answers */}
                  {ans.question.type === 'TEXT' && (
                    <div className="space-y-1 text-sm">
                      <div className="bg-gray-50 px-3 py-2 rounded">
                        <span className="text-gray-500 mr-2">Sizdin zhaup:</span>
                        <span className="font-medium">{ans.answer || '(zhaup zhoк)'}</span>
                      </div>
                      <div className="bg-green-50 px-3 py-2 rounded">
                        <span className="text-gray-500 mr-2">Durys zhaup:</span>
                        <span className="text-green-700 font-medium">{ans.question.answer}</span>
                      </div>
                    </div>
                  )}
                </div>

                <div className={`flex-shrink-0 text-sm font-semibold ${ans.isCorrect ? 'text-green-600' : 'text-red-600'}`}>
                  {ans.isCorrect === true ? '+1' : ans.isCorrect === false ? '0' : '—'}
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Proctor events */}
      {attempt.events.length > 0 && (
        <div className="card mt-6">
          <h2 className="text-lg font-semibold mb-4 text-orange-700">Proktering is-sharalary</h2>
          <div className="space-y-2">
            {attempt.events.map((ev) => (
              <div key={ev.id} className="flex items-center gap-3 text-sm py-1 border-b border-gray-100 last:border-0">
                <span className="text-orange-500">⚠</span>
                <span className="font-mono text-gray-700">{ev.type}</span>
                <span className="ml-auto text-gray-400 text-xs">
                  {new Date(ev.timestamp).toLocaleTimeString('kk-KZ')}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import api from '@/lib/api';
import Link from 'next/link';
import toast from 'react-hot-toast';

interface Answer {
  id: string;
  answer: string;
  isCorrect: boolean | null;
  question: {
    id: string;
    text: string;
    type: string;
    options: string[] | null;
    answer: string;
  };
}

interface Attempt {
  id: string;
  score: number | null;
  trustScore: number;
  status: string;
  startedAt: string;
  finishedAt: string | null;
  exam: {
    id: string;
    title: string;
    passScore: number;
    duration: number;
  };
  answers: Answer[];
  events: { id: string; type: string; timestamp: string }[];
}

const EVENT_LABELS: Record<string, string> = {
  TAB_SWITCH:       ' Қойынды ауыстыру',
  FULLSCREEN_EXIT:  ' Толық экраннан шығу',
  FACE_NOT_FOUND:   ' Бет анықталмады',
  MULTIPLE_FACES:   ' Бірнеше бет анықталды',
  COPY_PASTE:       ' Көшіру/қою',
  WINDOW_BLUR:      ' Терезеден шығу',
};

export default function AttemptReviewPage() {
  const { attemptId } = useParams<{ attemptId: string }>();
  const router = useRouter();
  const [attempt, setAttempt] = useState<Attempt | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api
      .get(`/attempts/${attemptId}`)
      .then(({ data }) => setAttempt(data))
      .catch(() => {
        toast.error('Жүктеу қатесі');
        router.push('/dashboard/my-attempts');
      })
      .finally(() => setLoading(false));
  }, [attemptId]);

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary-600" />
      </div>
    );
  }

  if (!attempt) return null;

  const passed = (attempt.score ?? 0) >= attempt.exam.passScore;
  const correctCount = attempt.answers.filter((a) => a.isCorrect).length;
  const duration = attempt.finishedAt
    ? Math.round((new Date(attempt.finishedAt).getTime() - new Date(attempt.startedAt).getTime()) / 60000)
    : null;

  const trustColor =
    attempt.trustScore >= 80 ? 'text-green-600' :
    attempt.trustScore >= 50 ? 'text-yellow-600' : 'text-red-600';

  const trustBarColor =
    attempt.trustScore >= 80 ? 'bg-green-500' :
    attempt.trustScore >= 50 ? 'bg-yellow-500' : 'bg-red-500';

  return (
    <div className="max-w-4xl">
      {/* Breadcrumb */}
      <div className="mb-6">
        <Link href="/dashboard/my-attempts" className="text-primary-600 hover:underline text-sm inline-flex items-center gap-1">
          ← Нәтижелерге оралу
        </Link>
      </div>

      {/* Summary card */}
      <div className={`card mb-6 border-2 ${passed ? 'border-green-400' : 'border-red-400'}`}>
        <div className="flex flex-wrap justify-between items-start gap-4">
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 flex-wrap mb-1">
              <span className={`inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-semibold ${passed ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                {passed ? '✅ Өтті' : '❌ Өтпеді'}
              </span>
              {attempt.status === 'FLAGGED' && (
                <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-semibold bg-orange-100 text-orange-800">
                   Күмәнді
                </span>
              )}
            </div>
            <h1 className="text-xl font-bold text-gray-900">{attempt.exam.title}</h1>
            <p className="text-gray-400 text-sm mt-1">
               {new Date(attempt.startedAt).toLocaleString('kk-KZ')}
              {duration !== null && <span className="ml-3">⏱ {duration} мин</span>}
            </p>
          </div>
          <div className="text-right">
            <p className={`text-4xl font-bold ${passed ? 'text-green-600' : 'text-red-600'}`}>
              {attempt.score ?? 0}%
            </p>
            <p className="text-sm text-gray-400 mt-0.5">өту шегі: {attempt.exam.passScore}%</p>
          </div>
        </div>

        {/* Stats row */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mt-5 pt-4 border-t border-gray-100">
          <div className="text-center">
            <p className="text-xl font-bold text-gray-900">{correctCount}/{attempt.answers.length}</p>
            <p className="text-xs text-gray-500 mt-0.5">Дұрыс жауаптар</p>
          </div>
          <div className="text-center">
            <p className={`text-xl font-bold ${trustColor}`}>{attempt.trustScore}%</p>
            <p className="text-xs text-gray-500 mt-0.5">Сенімділік</p>
          </div>
          <div className="text-center">
            <p className="text-xl font-bold text-orange-600">{attempt.events.length}</p>
            <p className="text-xs text-gray-500 mt-0.5">Іс-шаралар</p>
          </div>
          <div className="text-center">
            <p className="text-xl font-bold text-gray-700">{duration !== null ? `${duration} мин` : '—'}</p>
            <p className="text-xs text-gray-500 mt-0.5">Уақыт</p>
          </div>
        </div>

        {/* Trust bar */}
        <div className="mt-4">
          <div className="flex justify-between text-xs text-gray-400 mb-1">
            <span>Сенімділік деңгейі</span>
            <span className={`font-semibold ${trustColor}`}>{attempt.trustScore}%</span>
          </div>
          <div className="h-2 bg-gray-200 rounded-full overflow-hidden">
            <div
              className={`h-full ${trustBarColor} rounded-full transition-all`}
              style={{ width: `${attempt.trustScore}%` }}
            />
          </div>
        </div>
      </div>

      {/* Answers section */}
      <div className="mb-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-3">
           Сұрақтар мен жауаптар
        </h2>
        {attempt.answers.length === 0 ? (
          <div className="card text-center py-10 text-gray-400">
            <p className="text-4xl mb-2"></p>
            <p>Жауаптар жоқ</p>
          </div>
        ) : (
          <div className="space-y-3">
            {attempt.answers.map((ans, idx) => {
              const borderColor =
                ans.isCorrect === true ? 'border-l-green-500' :
                ans.isCorrect === false ? 'border-l-red-500' : 'border-l-gray-300';
              return (
                <div key={ans.id} className={`card border-l-4 ${borderColor}`}>
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex-1 min-w-0">
                      <p className="font-medium text-gray-900 mb-3">
                        <span className="text-primary-600 mr-2 font-bold">{idx + 1}.</span>
                        {ans.question.text}
                      </p>

                      {/* Options for choice questions */}
                      {ans.question.options && ans.question.options.length > 0 && (
                        <div className="space-y-1.5 mb-2">
                          {ans.question.options.map((opt, optIdx) => {
                            const isUserAnswer = ans.answer.split(',').map((s) => s.trim()).includes(opt);
                            const isCorrectAnswer = ans.question.answer.split(',').map((s) => s.trim()).includes(opt);
                            return (
                              <div
                                key={optIdx}
                                className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm ${
                                  isCorrectAnswer
                                    ? 'bg-green-50 border border-green-200 text-green-800'
                                    : isUserAnswer
                                    ? 'bg-red-50 border border-red-200 text-red-800'
                                    : 'bg-gray-50 text-gray-600'
                                }`}
                              >
                                <span className="text-base">
                                  {isCorrectAnswer ? '✓' : isUserAnswer ? '✗' : '○'}
                                </span>
                                <span className="flex-1">{opt}</span>
                                {isUserAnswer && !isCorrectAnswer && (
                                  <span className="text-xs bg-red-100 text-red-600 px-1.5 py-0.5 rounded">Сіздің жауап</span>
                                )}
                                {isCorrectAnswer && (
                                  <span className="text-xs bg-green-100 text-green-700 px-1.5 py-0.5 rounded font-semibold">Дұрыс жауап</span>
                                )}
                              </div>
                            );
                          })}
                        </div>
                      )}

                      {/* Text answers */}
                      {ans.question.type === 'TEXT' && (
                        <div className="space-y-1.5 text-sm">
                          <div className="bg-gray-50 border border-gray-200 px-3 py-2 rounded-lg">
                            <span className="text-gray-400 text-xs block mb-0.5">Сіздің жауап:</span>
                            <span className="font-medium">{ans.answer || '(жауап жоқ)'}</span>
                          </div>
                          <div className="bg-green-50 border border-green-200 px-3 py-2 rounded-lg">
                            <span className="text-gray-400 text-xs block mb-0.5">Дұрыс жауап:</span>
                            <span className="text-green-700 font-medium">{ans.question.answer}</span>
                          </div>
                        </div>
                      )}
                    </div>

                    <div className={`flex-shrink-0 text-sm font-bold px-2 py-1 rounded ${
                      ans.isCorrect === true ? 'bg-green-100 text-green-700' :
                      ans.isCorrect === false ? 'bg-red-100 text-red-600' : 'bg-gray-100 text-gray-500'
                    }`}>
                      {ans.isCorrect === true ? '+1' : ans.isCorrect === false ? '0' : '—'}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Proctor events */}
      {attempt.events.length > 0 && (
        <div className="card border border-orange-200 bg-orange-50">
          <h2 className="text-lg font-semibold mb-4 text-orange-700 flex items-center gap-2">
             Проктеринг іс-шаралары
            <span className="text-sm font-normal bg-orange-100 text-orange-600 px-2 py-0.5 rounded-full">
              {attempt.events.length}
            </span>
          </h2>
          <div className="space-y-2">
            {attempt.events.map((ev) => (
              <div key={ev.id} className="flex items-center gap-3 text-sm py-2 px-3 bg-white rounded-lg border border-orange-100">
                <span className="flex-1 text-gray-700">
                  {EVENT_LABELS[ev.type] ?? `⚠ ${ev.type}`}
                </span>
                <span className="text-gray-400 text-xs font-mono">
                  {new Date(ev.timestamp).toLocaleTimeString('kk-KZ')}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

#!/usr/bin/env python3 """ ProctoLearn — генератор 20 уроков (4 модуля × 5 уроков) для каждого курса """ import subprocess, uuid, json from datetime import datetime
DB = "proctolearn_db" USER = "proctolearn" CONTAINER = "proctolearn_postgres"
def psql(sql): result = subprocess.run( ["docker", "exec", CONTAINER, "psql", "-U", USER, "-d", DB, "-t", "-A", "-F", "\t", "-c", sql], capture_output=True, text=True ) return result.stdout.strip()
def psql_cmd(sql): subprocess.run( ["docker", "exec", CONTAINER, "psql", "-U", USER, "-d", DB, "-c", sql], capture_output=True, text=True )
